   165→
   166→/// Output format modes for parade command
   167→#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
   168→pub enum jjrq_ParadeFormat {
   169→    /// One line per pace: [state] silks (₢coronet)
   170→    Overview,
   171→    /// Numbered list: N. [state] silks (₢coronet)
   172→    Order,
   173→    /// Full tack text for one pace (requires --pace)
   174→    Detail,
   175→    /// Paddock + all paces with tack text (default)
   176→    #[default]
   177→    Full,
   178→}
   179→
   180→/// Arguments for parade command
   181→#[derive(Debug)]
   182→pub struct jjrq_ParadeArgs {
   183→    pub file: std::path::PathBuf,
   184→    pub firemark: Firemark,
   185→    pub format: jjrq_ParadeFormat,
   186→    pub pace: Option<String>,
   187→}
   188→
   189→/// Run the parade command - display comprehensive Heat status
   190→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   191→    // Validate: detail format requires --pace
   192→    if args.format == jjrq_ParadeFormat::Detail && args.pace.is_none() {
   193→        eprintln!("jjx_parade: error: --format detail requires --pace <coronet>");
   194→        return 1;
   195→    }
   196→
   197→    let gallops = match Gallops::jjrg_load(&args.file) {
   198→        Ok(g) => g,
   199→        Err(e) => {
   200→            eprintln!("jjx_parade: error: {}", e);
   201→            return 1;
   202→        }
   203→    };
   204→
   205→    let heat_key = args.firemark.jjrf_display();
   206→    let heat = match gallops.heats.get(&heat_key) {
   207→        Some(h) => h,
   208→        None => {
   209→            eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   210→            return 1;
   211→        }
   212→    };
   213→
   214→    match args.format {
   215→        jjrq_ParadeFormat::Overview => {
   216→            for coronet_key in &heat.order {
   217→                if let Some(pace) = heat.paces.get(coronet_key) {
   218→                    if let Some(tack) = pace.tacks.first() {
   219→                        let state_str = zjjrq_pace_state_str(&tack.state);
   220→                        println!("[{}] {} ({})", state_str, pace.silks, coronet_key);
   221→                    }
   222→                }
   223→            }
   224→        }
   225→        jjrq_ParadeFormat::Order => {
   226→            for (idx, coronet_key) in heat.order.iter().enumerate() {
   227→                if let Some(pace) = heat.paces.get(coronet_key) {
   228→                    if let Some(tack) = pace.tacks.first() {
   229→                        let state_str = zjjrq_pace_state_str(&tack.state);
   230→                        println!("{}. [{}] {} ({})", idx + 1, state_str, pace.silks, coronet_key);
   231→                    }
   232→                }
   233→            }
   234→        }
   235→        jjrq_ParadeFormat::Detail => {
   236→            let target_coronet = args.pace.as_ref().unwrap();
   237→            let pace = match heat.paces.get(target_coronet) {
   238→                Some(p) => p,
   239→                None => {
   240→                    eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", target_coronet, heat_key);
   241→                    return 1;
   242→                }
   243→            };
   244→            if let Some(tack) = pace.tacks.first() {
   245→                let state_str = zjjrq_pace_state_str(&tack.state);
   246→                println!("Pace: {} ({})", pace.silks, target_coronet);
   247→                println!("State: {}", state_str);
   248→                println!("Heat: {}", heat_key);
   249→                println!();
   250→                println!("{}", tack.text);
   251→                if let Some(ref direction) = tack.direction {
   252→                    println!();
   253→                    println!("Direction: {}", direction);
   254→                }
   255→            }
   256→        }
   257→        jjrq_ParadeFormat::Full => {
   258→            // Read paddock file content
   259→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   260→                Ok(content) => content,
   261→                Err(e) => {
   262→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   263→                    return 1;
   264→                }
   265→            };
   266→
   267→            let status_str = match heat.status {
   268→                HeatStatus::Current => "current",
   269→                HeatStatus::Retired => "retired",
   270→            };
   271→
   272→            println!("Heat: {} ({})", heat.silks, heat_key);
   273→            println!("Status: {}", status_str);
   274→            println!("Created: {}", heat.creation_time);
   275→            println!();
   276→            println!("## Paddock");
   277→            println!();
   278→            println!("{}", paddock_content);
   279→            println!();
   280→            println!("## Paces");
   281→            println!();
   282→
   283→            for coronet_key in &heat.order {
   284→                if let Some(pace) = heat.paces.get(coronet_key) {
   285→                    if let Some(tack) = pace.tacks.first() {
   286→                        let state_str = zjjrq_pace_state_str(&tack.state);
   287→                        println!("### {} ({}) [{}]", pace.silks, coronet_key, state_str);
   288→                        println!();
   289→                        println!("{}", tack.text);
   290→                        if let Some(ref direction) = tack.direction {
   291→                            println!();
   292→                            println!("**Direction:** {}", direction);
   293→                        }
   294→                        println!();
   295→                    }
   296→                }
   297→            }
   298→        }
   299→    }
   300→
   301→    0
   302→}
   303→
   304→/// Helper to convert PaceState to display string
   305→fn zjjrq_pace_state_str(state: &PaceState) -> &'static str {
   306→    match state {
   307→        PaceState::Rough => "rough",
   308→        PaceState::Primed => "primed",
   309→        PaceState::Complete => "complete",
   310→        PaceState::Abandoned => "abandoned",
   311→    }
   312→}
