   336→    // steeplechase: Vec<SteeplechaseEntry>,
   337→}
   338→
   339→/// Pace structure for retire output (full tack history)
   340→#[derive(Serialize)]
   341→struct zjjrq_RetirePace {
   342→    coronet: String,
   343→    silks: String,
   344→    tacks: Vec<zjjrq_RetireTack>,
   345→}
   346→
   347→/// Tack structure for retire output
   348→#[derive(Serialize)]
   349→struct zjjrq_RetireTack {
   350→    ts: String,
   351→    state: String,
   352→    text: String,
   353→    #[serde(skip_serializing_if = "Option::is_none")]
   354→    direction: Option<String>,
   355→}
   356→
   357→/// Run the retire command - extract complete Heat data for archival
   358→pub fn jjrq_run_retire(args: jjrq_RetireArgs) -> i32 {
   359→    let gallops = match Gallops::jjrg_load(&args.file) {
   360→        Ok(g) => g,
   361→        Err(e) => {
   362→            eprintln!("jjx_retire: error: {}", e);
   363→            return 1;
   364→        }
   365→    };
   366→
   367→    let heat_key = args.firemark.jjrf_display();
   368→    let heat = match gallops.heats.get(&heat_key) {
   369→        Some(h) => h,
   370→        None => {
   371→            eprintln!("jjx_retire: error: Heat '{}' not found", heat_key);
   372→            return 1;
   373→        }
   374→    };
   375→
   376→    // Read paddock file content
   377→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   378→        Ok(content) => content,
   379→        Err(e) => {
   380→            eprintln!("jjx_retire: error reading paddock file '{}': {}", heat.paddock_file, e);
   381→            return 1;
   382→        }
   383→    };
   384→
   385→    // Build paces array with full tack history, ordered per Heat's order array
   386→    let mut paces = Vec::new();
   387→    for coronet_key in &heat.order {
   388→        if let Some(pace) = heat.paces.get(coronet_key) {
   389→            let tacks: Vec<zjjrq_RetireTack> = pace.tacks.iter().map(|tack| {
   390→                zjjrq_RetireTack {
   391→                    ts: tack.ts.clone(),
   392→                    state: match tack.state {
   393→                        PaceState::Rough => "rough".to_string(),
   394→                        PaceState::Primed => "primed".to_string(),
   395→                        PaceState::Complete => "complete".to_string(),
   396→                        PaceState::Abandoned => "abandoned".to_string(),
   397→                    },
   398→                    text: tack.text.clone(),
   399→                    direction: tack.direction.clone(),
   400→                }
   401→            }).collect();
   402→
   403→            paces.push(zjjrq_RetirePace {
   404→                coronet: coronet_key.clone(),
   405→                silks: pace.silks.clone(),
   406→                tacks,
   407→            });
   408→        }
   409→    }
   410→
   411→    let output = zjjrq_RetireOutput {
   412→        firemark: heat_key.clone(),
   413→        silks: heat.silks.clone(),
   414→        created: heat.creation_time.clone(),
   415→        status: match heat.status {
   416→            HeatStatus::Current => "current".to_string(),
   417→            HeatStatus::Retired => "retired".to_string(),
   418→        },
   419→        paddock_file: heat.paddock_file.clone(),
   420→        paddock_content,
   421→        paces,
   422→        // TODO: Call jjx_rein internally to get steeplechase entries
   423→    };
   424→
   425→    // Output JSON
   426→    match serde_json::to_string_pretty(&output) {
   427→        Ok(json) => {
   428→            println!("{}", json);
   429→            0
   430→        }
   431→        Err(e) => {
   432→            eprintln!("jjx_retire: error serializing output: {}", e);
   433→            1
   434→        }
   435→    }
   436→}
