#[cfg(test)]
mod tests {
    use super::*;
    use crate::jjrg_gallops::{jjrg_Heat as Heat, jjrg_Pace as Pace, jjrg_Tack as Tack};
    use std::collections::BTreeMap;

    fn create_test_gallops() -> Gallops {
        let mut paces = BTreeMap::new();
        paces.insert(
            "₢ABAAA".to_string(),
            Pace {
                silks: "test-pace-one".to_string(),
